import React, { Component } from 'react';


export default class AnalogSub extends Component {
    constructor(props) {
        super(props);
        this.state = {
                    title: props.title,
                    pic: props.pic, 
                    link: props.link
                    };
    }

    render() {
        return (
            <div>
                <h3>{this.state.title}</h3>
                <img src={this.state.pic} alt={title} />
                <a href={this.state.link}>Youtube Link</a>
            </div>

        )
    }

};
